Lambda is used in DE for: S3 event triggers (run Glue on new file), scheduled lightweight transforms, and fan-out messaging via SNS/SQS.

```hcl
# Package the Lambda code
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_dir  = "${path.module}/lambda_src"
  output_path = "${path.module}/lambda.zip"
}

# Lambda function
resource "aws_lambda_function" "s3_trigger" {
  function_name    = "s3-new-file-trigger"
  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  handler          = "handler.main"
  runtime          = "python3.12"
  role             = aws_iam_role.lambda_exec.arn
  timeout          = 300
  memory_size      = 512

  environment {
    variables = {
      GLUE_JOB_NAME = aws_glue_job.etl.name
      ENV           = var.environment
    }
  }
}

# S3 notification to trigger Lambda on new objects
resource "aws_s3_bucket_notification" "data_lake" {
  bucket = aws_s3_bucket.data_lake.id
  lambda_function {
    lambda_function_arn = aws_lambda_function.s3_trigger.arn
    events              = ["s3:ObjectCreated:*"]
    filter_prefix       = "raw/"
  }
}

resource "aws_lambda_permission" "s3_invoke" {
  statement_id  = "AllowS3Invoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.s3_trigger.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.data_lake.arn
}
```

source_code_hash: forces Lambda update when code changes.
